import 'package:vector_math/vector_math.dart';

FractalViewState _view(double zoom) {
  return FractalViewState(
    pan: Vector2.zero(),
    zoom: zoom,
    rotation: Vector3.zero(),
  );
}

Map<String, Object?> _entryJson(double zoom) {
  return HistoryEntry.fromState(
    moduleId: 'mandelbrot',
    view: _view(zoom),
    params: const <String, Object>{'iterations': 100},
  ).toJson();
}

Future<void> _recordAndFlush(
  WidgetTester tester,
  HistoryProvider provider, {
  required double zoom,
}) async {
  provider.recordLocation(
    moduleId: 'mandelbrot',
    view: _view(zoom),
    params: const <String, Object>{'iterations': 100},
  );
  await tester.pump(const Duration(milliseconds: 501));
}

final class _LegacyReplayController {
  final params = <String, Object>{};
  double? zoom;
  Vector2? pan;
  Vector3? rotation;

  void updateParam(String id, Object value) {
    params[id] = value;
  }

  void updateZoom(double value) {
    zoom = value;
  }

  void updatePan(Vector2 value) {
    pan = Vector2.copy(value);
  }

  void updateRotation(Vector3 value) {
    rotation = Vector3.copy(value);
  }
}

void main() {
  group('HistoryProvider navigation recording', () {
    setUp(() {
      TestWidgetsFlutterBinding.ensureInitialized();
      SharedPreferences.setMockInitialValues({});
    });

    testWidgets(
        'replaying the current back entry does not truncate forward history',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      await _recordAndFlush(tester, provider, zoom: 1);
      await _recordAndFlush(tester, provider, zoom: 2);
      await _recordAndFlush(tester, provider, zoom: 3);

      final restored = provider.goBack();
      expect(restored, isNotNull);
      expect(provider.currentPosition, 2);
      expect(provider.canGoForward, isTrue);

      await _recordAndFlush(tester, provider, zoom: 2);

      expect(provider.historyCount, 3);
      expect(provider.currentPosition, 2);
      expect(provider.canGoForward, isTrue);
      expect(provider.currentEntry, same(restored));
    });

    testWidgets('history navigation cancels pending pre-navigation records',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      await _recordAndFlush(tester, provider, zoom: 1);
      await _recordAndFlush(tester, provider, zoom: 2);

      provider.recordLocation(
        moduleId: 'mandelbrot',
        view: _view(3),
        params: const <String, Object>{'iterations': 100},
      );

      final restored = provider.goBack();
      expect(restored, isNotNull);
      expect(restored!.view.zoom, 1);
      expect(provider.currentPosition, 1);
      expect(provider.canGoForward, isTrue);

      await tester.pump(const Duration(milliseconds: 501));

      expect(provider.historyCount, 2);
      expect(provider.currentPosition, 1);
      expect(provider.currentEntry, same(restored));
      expect(provider.canGoForward, isTrue);
      expect(provider.history.map((entry) => entry.view.zoom), [1, 2]);
    });

    testWidgets('records the state passed to the debounced record call',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      final pan = Vector2(1, 2);
      final rotation = Vector3(3, 4, 5);
      final params = <String, Object>{'iterations': 100};
      provider.recordLocation(
        moduleId: 'mandelbrot',
        view: FractalViewState(pan: pan, zoom: 6, rotation: rotation),
        params: params,
      );

      pan.setValues(7, 8);
      rotation.setValues(9, 10, 11);
      params['iterations'] = 250;
      await tester.pump(const Duration(milliseconds: 501));

      final entry = provider.currentEntry;
      expect(entry, isNotNull);
      expect(entry!.view.pan.x, 1);
      expect(entry.view.pan.y, 2);
      expect(entry.view.rotation.x, 3);
      expect(entry.view.rotation.y, 4);
      expect(entry.view.rotation.z, 5);
      expect(entry.params, {'iterations': 100});
    });

    testWidgets('keeps in-memory history capped to the persisted max depth',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      for (var i = 0; i < HistoryStore.maxHistoryEntries + 2; i++) {
        await _recordAndFlush(tester, provider, zoom: i + 1.0);
      }

      expect(provider.historyCount, HistoryStore.maxHistoryEntries);
      expect(provider.currentPosition, HistoryStore.maxHistoryEntries);
      expect(provider.history.first.view.zoom, 3.0);
      expect(provider.currentEntry!.view.zoom, 102.0);
    });

    testWidgets('keeps in-memory favorites capped to persisted max depth',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      await _recordAndFlush(tester, provider, zoom: 1);

      for (var i = 0; i < HistoryStore.maxFavoriteEntries + 2; i++) {
        await provider.saveCurrentAsFavorite('favorite $i');
      }

      expect(provider.favoritesCount, HistoryStore.maxFavoriteEntries);
      expect(provider.favorites.first.name, 'favorite 2');
      expect(provider.favorites.last.name, 'favorite 501');
      expect(store.loadFavorites().length, HistoryStore.maxFavoriteEntries);
    });

    testWidgets('restored history and favorites are capped before display',
        (tester) async {
      SharedPreferences.setMockInitialValues({
        'exploration_history': jsonEncode([
          for (var i = 0; i < HistoryStore.maxHistoryEntries + 2; i++)
            _entryJson(i + 1.0),
        ]),
        'exploration_favorites': jsonEncode([
          for (var i = 0; i < HistoryStore.maxFavoriteEntries + 2; i++)
            _entryJson(i + 1.0),
        ]),
      });

      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      expect(provider.historyCount, HistoryStore.maxHistoryEntries);
      expect(provider.currentPosition, HistoryStore.maxHistoryEntries);
      expect(provider.history.first.view.zoom, 3.0);
      expect(provider.currentEntry!.view.zoom, 102.0);
      expect(provider.favoritesCount, HistoryStore.maxFavoriteEntries);
      expect(provider.favorites.first.view.zoom, 3.0);
      expect(provider.favorites.last.view.zoom, 502.0);
    });

    testWidgets('clearHistory cancels pending debounced records',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      provider.recordLocation(
        moduleId: 'mandelbrot',
        view: _view(6),
        params: const <String, Object>{'iterations': 100},
      );
      await provider.clearHistory();
      await tester.pump(const Duration(milliseconds: 501));

      expect(provider.historyCount, 0);
      expect(provider.currentEntry, isNull);
      expect(store.loadHistory(), isEmpty);
    });

    testWidgets('history replay switches to the recorded module before state',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      final registry = ModuleRegistry();
      final controller = FractalController(registry);
      addTearDown(controller.dispose);

      final entry = HistoryEntry(
        id: 'julia-replay',
        moduleId: 'julia',
        view: FractalViewState(
          pan: Vector2(0.25, -0.5),
          zoom: 2.5,
          rotation: Vector3(0.1, 0.2, 0.3),
        ),
        params: const <String, Object>{
          'iterations': 222,
          'bailout': 4.5,
          'colorScheme': 2,
        },
        visitedAt: DateTime.utc(2024),
      );

      provider.applyToController(entry, controller);

      expect(controller.module.id, 'julia');
      expect(controller.params['iterations'], 222);
      expect(controller.params['bailout'], closeTo(4.5, 1e-12));
      expect(controller.params['colorScheme'], 2);
      expect(controller.view.pan, Vector2(0.25, -0.5));
      expect(controller.view.zoom, 2.5);
      expect(controller.view.rotation, Vector3(0.1, 0.2, 0.3));
    });

    testWidgets('history replay keeps legacy structural controllers working',
        (tester) async {
      final store = await HistoryStore.create();
      final provider = HistoryProvider(store: store);
      addTearDown(provider.dispose);

      final controller = _LegacyReplayController();
      final entry = HistoryEntry(
        id: 'legacy-replay',
        moduleId: 'mandelbrot',
        view: FractalViewState(
          pan: Vector2(-0.25, 0.5),
          zoom: 3.5,
          rotation: Vector3(0.4, 0.5, 0.6),
        ),
        params: const <String, Object>{'iterations': 180},
        visitedAt: DateTime.utc(2024),
      );

      provider.applyToController(entry, controller);

      expect(controller.params, {'iterations': 180});
      expect(controller.zoom, 3.5);
      expect(controller.pan, Vector2(-0.25, 0.5));
      expect(controller.rotation, Vector3(0.4, 0.5, 0.6));
    });
  });
}

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:flutter_fractals/features/history/history_entry.dart';

/// Persists exploration history and favorites to local storage.
///
/// History entries are stored in SharedPreferences as JSON.
/// Maintains separate storage for:
/// - Navigation history (limited size, auto-trimmed)
/// - Favorites (unlimited, user-managed)
///
/// {@category Services}
class HistoryStore {
  final SharedPreferences _prefs;

  static const String _historyKey = 'exploration_history';
  static const String _favoritesKey = 'exploration_favorites';
  static const int maxHistoryEntries = 100;
  static const int maxFavoriteEntries = 500;

  HistoryStore._(this._prefs);

  /// Creates a new [HistoryStore] instance.
  static Future<HistoryStore> create() async {
    final prefs = await SharedPreferences.getInstance();
    return HistoryStore._(prefs);
  }

  /// Loads the navigation history.
  ///
  /// Returns entries in chronological order (oldest first).
  List<HistoryEntry> loadHistory() => _loadEntries(_historySlot);

  /// Saves the navigation history.
  ///
  /// Automatically trims to [maxHistoryEntries].
  Future<void> saveHistory(List<HistoryEntry> entries) async {
    await _saveEntries(_historySlot, entries);
  }

  /// Loads the user's favorite locations.
  List<HistoryEntry> loadFavorites() => _loadEntries(_favoritesSlot);

  /// Saves the user's favorite locations.
  ///
  /// Capped at [maxFavoriteEntries] to prevent unbounded storage growth.
  Future<void> saveFavorites(List<HistoryEntry> favorites) async {
    await _saveEntries(_favoritesSlot, favorites);
  }

  /// Adds an entry to favorites.
  Future<void> addFavorite(HistoryEntry entry) async {
    final favorites = loadFavorites();
    // Check if already exists by ID
    if (favorites.any((f) => f.id == entry.id)) return;
    favorites.add(entry);
    await saveFavorites(favorites);
  }

  /// Removes an entry from favorites by ID.
  Future<void> removeFavorite(String entryId) async {
    final favorites = loadFavorites();
    final updated = favorites.where((f) => f.id != entryId).toList();
    await saveFavorites(updated);
  }

  /// Clears all navigation history.
  Future<void> clearHistory() async {
    await _prefs.remove(_historyKey);
  }

  /// Clears all favorites.
  Future<void> clearFavorites() async {
    await _prefs.remove(_favoritesKey);
  }

  List<HistoryEntry> _loadEntries(_HistoryStoreSlot slot) {
    final payload = _prefs.getString(slot.key);
    return _HistoryEntryCodec.parse(payload, slotLabel: slot.label);
  }

  Future<void> _saveEntries(
    _HistoryStoreSlot slot,
    List<HistoryEntry> entries,
  ) async {
    final bounded = slot.mostRecent(entries);
    await _prefs.setString(slot.key, _HistoryEntryCodec.serialize(bounded));
  }
}

const _historySlot = _HistoryStoreSlot(
  key: HistoryStore._historyKey,
  label: 'history',
  maxEntries: HistoryStore.maxHistoryEntries,
);

const _favoritesSlot = _HistoryStoreSlot(
  key: HistoryStore._favoritesKey,
  label: 'favorites',
  maxEntries: HistoryStore.maxFavoriteEntries,
);

/// Storage contract for one SharedPreferences-backed history collection.
///
/// Entries are expected oldest-first. When a slot exceeds its cap, the oldest
/// entries are dropped and the most recent tail is retained.
class _HistoryStoreSlot {
  final String key;
  final String label;
  final int maxEntries;

  const _HistoryStoreSlot({
    required this.key,
    required this.label,
    required this.maxEntries,
  }) : assert(maxEntries > 0);

  List<HistoryEntry> mostRecent(List<HistoryEntry> entries) {
    if (entries.length <= maxEntries) return entries;
    return entries.sublist(entries.length - maxEntries);
  }
}

class _HistoryEntryCodec {
  const _HistoryEntryCodec._();

  static List<HistoryEntry> parse(String? payload,
      {required String slotLabel}) {
    if (payload == null || payload.isEmpty) return [];
    try {
      final decoded = jsonDecode(payload) as List;
      final entries = <HistoryEntry>[];
      for (final item in decoded) {
        try {
          final entry =
              HistoryEntry.fromJson((item as Map).cast<String, Object?>());
          entries.add(entry);
        } catch (e) {
          // Skip corrupted entry, continue with others.
          if (kDebugMode) {
            debugPrint('Failed to parse $slotLabel entry: $e');
          }
        }
      }
      return entries;
    } catch (e) {
      // Corrupted JSON, return empty list.
      if (kDebugMode) debugPrint('Failed to parse $slotLabel JSON: $e');
      return [];
    }
  }

  static String serialize(List<HistoryEntry> entries) {
    return jsonEncode(entries.map((e) => e.toJson()).toList());
  }
}

import 'package:flutter_fractals/core/models/export_options.dart';

const int defaultCustomExportWidth = 1920;
const int defaultCustomExportHeight = 1080;

/// Provenance for the custom export dimension that wins resolution.
enum CustomExportDimensionSource {
  fieldText,
  currentValue,
  fallback,
}

/// Replayable result of resolving one custom export dimension.
///
/// The export model clamps target dimensions later, but the sheet summary and
/// submission payload read [ExportOptions.customWidth]/customHeight directly.
/// Keep that boundary normalized too so all export dimension paths share the
/// same safety contract.
final class CustomExportDimensionResolution {
  const CustomExportDimensionResolution({
    required this.value,
    required this.source,
    required this.wasClamped,
  });

  final int value;
  final CustomExportDimensionSource source;
  final bool wasClamped;
}

CustomExportDimensionResolution resolveCustomExportDimensionPlan({
  required String fieldText,
  required int? currentValue,
  required int fallback,
}) {
  final parsed = int.tryParse(fieldText.trim());
  return _normalizeCustomExportDimension(
        parsed,
        source: CustomExportDimensionSource.fieldText,
      ) ??
      _normalizeCustomExportDimension(
        currentValue,
        source: CustomExportDimensionSource.currentValue,
      ) ??
      _normalizeFallbackCustomExportDimension(fallback);
}

int resolveCustomExportDimension({
  required String fieldText,
  required int? currentValue,
  required int fallback,
}) {
  return resolveCustomExportDimensionPlan(
    fieldText: fieldText,
    currentValue: currentValue,
    fallback: fallback,
  ).value;
}

CustomExportDimensionResolution? _normalizeCustomExportDimension(
  int? value, {
  required CustomExportDimensionSource source,
}) {
  final normalized = ExportDimensionPolicy.positiveCustomDimension(value);
  if (normalized == null) return null;

  return CustomExportDimensionResolution(
    value: normalized,
    source: source,
    wasClamped: normalized != value,
  );
}

CustomExportDimensionResolution _normalizeFallbackCustomExportDimension(
  int fallback,
) {
  final safeFallback = fallback > 0 ? fallback : 1;
  final normalized = ExportDimensionPolicy.positiveCustomDimension(
    safeFallback,
  )!;

  return CustomExportDimensionResolution(
    value: normalized,
    source: CustomExportDimensionSource.fallback,
    wasClamped: normalized != fallback,
  );
}

ExportOptions withResolvedCustomExportDimensions({
  required ExportOptions options,
  required String widthText,
  required String heightText,
}) {
  return options.copyWith(
    customWidth: resolveCustomExportDimension(
      fieldText: widthText,
      currentValue: options.customWidth,
      fallback: defaultCustomExportWidth,
    ),
    customHeight: resolveCustomExportDimension(
      fieldText: heightText,
      currentValue: options.customHeight,
      fallback: defaultCustomExportHeight,
    ),
  );
}

import 'dart:async';
import 'package:flutter/material.dart';
import 'package:vector_math/vector_math.dart' hide Colors;

/// Replayable decision for [AnimatedFractalController.animateParameter].
///
/// Parameter animation only supports numeric interpolation. Keeping that
/// contract explicit prevents unsupported boolean/string changes from arming a
/// transition that no animation can ever complete.
enum AnimatedParameterTransitionKind {
  unchanged,
  numeric,
  unsupported,
}

/// Pure parameter-transition plan derived from two parameter values.
final class AnimatedParameterTransitionPlan {
  final AnimatedParameterTransitionKind kind;
  final double? fromValue;
  final double? toValue;

  const AnimatedParameterTransitionPlan._({
    required this.kind,
    this.fromValue,
    this.toValue,
  });

  factory AnimatedParameterTransitionPlan.fromValues(Object from, Object to) {
    if (from == to) {
      return const AnimatedParameterTransitionPlan._(
        kind: AnimatedParameterTransitionKind.unchanged,
      );
    }

    if (from is num && to is num) {
      return AnimatedParameterTransitionPlan._(
        kind: AnimatedParameterTransitionKind.numeric,
        fromValue: from.toDouble(),
        toValue: to.toDouble(),
      );
    }

    return const AnimatedParameterTransitionPlan._(
      kind: AnimatedParameterTransitionKind.unsupported,
    );
  }

  bool get startsTransition => kind == AnimatedParameterTransitionKind.numeric;
}

/// Replayable frame plan for timer-driven animations.
///
/// Morph timers derive curve input from a duration and frame cadence. Keeping
/// that conversion explicit prevents sub-frame durations from producing zero
/// total steps and sending Infinity/NaN into Flutter curves.
final class AnimatedTimelinePlan {
  static const int defaultFramesPerSecond = 60;

  final Duration duration;
  final int framesPerSecond;
  final Duration frameInterval;
  final int totalFrames;

  const AnimatedTimelinePlan._({
    required this.duration,
    required this.framesPerSecond,
    required this.frameInterval,
    required this.totalFrames,
  })  : assert(framesPerSecond > 0, 'framesPerSecond must be positive'),
        assert(frameInterval > Duration.zero, 'frameInterval must be positive'),
        assert(totalFrames > 0, 'totalFrames must be positive');

  factory AnimatedTimelinePlan.forDuration(
    Duration duration, {
    int framesPerSecond = defaultFramesPerSecond,
  }) {
    final safeFramesPerSecond =
        framesPerSecond > 0 ? framesPerSecond : defaultFramesPerSecond;
    final frameIntervalMs = 1000 ~/ safeFramesPerSecond;
    final rawFrames = duration.inMicroseconds <= 0
        ? 1
        : (duration.inMicroseconds *
                safeFramesPerSecond /
                Duration.microsecondsPerSecond)
            .round();

    return AnimatedTimelinePlan._(
      duration: duration,
      framesPerSecond: safeFramesPerSecond,
      frameInterval: Duration(
        milliseconds: frameIntervalMs > 0 ? frameIntervalMs : 1,
      ),
      totalFrames: rawFrames > 0 ? rawFrames : 1,
    );
  }

  bool get isImmediate => duration <= Duration.zero;

  double progressForFrame(int frame) {
    if (frame <= 0) return 0.0;
    return (frame / totalFrames).clamp(0.0, 1.0).toDouble();
  }

  bool isCompleteFrame(int frame) => frame >= totalFrames;
}

/// Replayable progress contract for elapsed timer animations.
///
/// Parameter/view animations are driven by wall-clock elapsed time. A
/// non-positive duration is an immediate transition, matching morph timelines;
/// otherwise a negative duration can leave an animation permanently at 0%.
final class AnimatedElapsedProgress {
  final Duration duration;
  final Duration elapsed;

  const AnimatedElapsedProgress({
    required this.duration,
    required this.elapsed,
  });

  double get value {
    if (duration <= Duration.zero) return 1.0;
    if (elapsed <= Duration.zero) return 0.0;
    return (elapsed.inMicroseconds / duration.inMicroseconds)
        .clamp(0.0, 1.0)
        .toDouble();
  }

  bool get isComplete => value >= 1.0;
}

/// Service that manages smooth animated transitions for fractal parameters.
///
/// This service provides interpolated values for parameters during transitions,
/// enabling smooth morphing effects when changing fractal settings.
class AnimatedFractalController extends ChangeNotifier {
  /// Animation duration for parameter changes.
  final Duration parameterDuration;

  /// Animation duration for module (fractal type) changes.
  final Duration morphDuration;

  /// Animation curve for transitions.
  final Curve curve;

  // Internal state
  final Map<String, _AnimatedValue> _animatedParams = {};
  _AnimatedValue<double>? _animatedZoom;
  _AnimatedValue<Vector2>? _animatedPan;
  _AnimatedValue<Vector3>? _animatedRotation;

  String? _previousModuleId;
  String? _currentModuleId;
  double _morphProgress = 1.0;
  Timer? _morphTimer;
  Timer? _celebrationTimer;

  bool _isCelebrating = false;
  bool _isTransitioning = false;

  // Interesting spot detection
  int _interestingSpotCount = 0;
  DateTime? _lastInterestingSpotTime;
  final _interestingSpotController = StreamController<void>.broadcast();

  AnimatedFractalController({
    this.parameterDuration = const Duration(milliseconds: 250),
    this.morphDuration = const Duration(milliseconds: 600),
    this.curve = Curves.easeOutCubic,
  });

  /// Stream that emits when an interesting spot is found.
  Stream<void> get onInterestingSpot => _interestingSpotController.stream;

  /// Whether a celebration effect should be shown.
  bool get isCelebrating => _isCelebrating;

  /// Whether the controller is currently transitioning between states.
  bool get isTransitioning => _isTransitioning;

  /// Progress of the current morph transition (0.0 to 1.0).
  double get morphProgress => _morphProgress;

  /// The previous module ID during a morph transition.
  String? get previousModuleId => _previousModuleId;

  /// The current module ID.
  String? get currentModuleId => _currentModuleId;

  /// Start a parameter transition.
  void animateParameter(String id, Object from, Object to) {
    final plan = AnimatedParameterTransitionPlan.fromValues(from, to);
    if (!plan.startsTransition) return;

    _isTransitioning = true;
    notifyListeners();

    _animatedParams[id] = _AnimatedValue<double>(
      from: plan.fromValue!,
      to: plan.toValue!,
      duration: parameterDuration,
      curve: curve,
      onComplete: () {
        _animatedParams.remove(id);
        _checkTransitionComplete();
      },
    );

    notifyListeners();
  }

  /// Animate zoom level transition.
  void animateZoom(double from, double to) {
    if (from == to) return;

    _isTransitioning = true;
    _animatedZoom = _AnimatedValue<double>(
      from: from,
      to: to,
      duration: parameterDuration,
      curve: curve,
      onComplete: () {
        _animatedZoom = null;
        _checkTransitionComplete();
      },
    );
    notifyListeners();
  }

  /// Animate pan transition.
  void animatePan(Vector2 from, Vector2 to) {
    if (from.x == to.x && from.y == to.y) return;

    _isTransitioning = true;
    _animatedPan = _AnimatedValue<Vector2>(
      from: from.clone(),
      to: to.clone(),
      duration: parameterDuration,
      curve: curve,
      onComplete: () {
        _animatedPan = null;
        _checkTransitionComplete();
      },
    );
    notifyListeners();
  }

  /// Animate rotation transition.
  void animateRotation(Vector3 from, Vector3 to) {
    if (from.x == to.x && from.y == to.y && from.z == to.z) return;

    _isTransitioning = true;
    _animatedRotation = _AnimatedValue<Vector3>(
      from: from.clone(),
      to: to.clone(),
      duration: parameterDuration,
      curve: curve,
      onComplete: () {
        _animatedRotation = null;
        _checkTransitionComplete();
      },
    );
    notifyListeners();
  }

  /// Start a module morph transition.
  void startMorph(String fromModuleId, String toModuleId) {
    if (fromModuleId == toModuleId) return;

    _previousModuleId = fromModuleId;
    _currentModuleId = toModuleId;
    _morphProgress = 0.0;
    _isTransitioning = true;

    _morphTimer?.cancel();

    final timeline = AnimatedTimelinePlan.forDuration(morphDuration);
    if (timeline.isImmediate) {
      _finishMorphTransition();
      notifyListeners();
      return;
    }

    var step = 0;

    _morphTimer = Timer.periodic(
      timeline.frameInterval,
      (timer) {
        step++;
        _morphProgress = curve.transform(timeline.progressForFrame(step));
        notifyListeners();

        if (timeline.isCompleteFrame(step)) {
          timer.cancel();
          _finishMorphTransition();
          notifyListeners();
        }
      },
    );

    notifyListeners();
  }

  /// Get the interpolated value for a parameter.
  Object? getInterpolatedValue(String id, Object currentValue) {
    final animated = _animatedParams[id];
    if (animated == null) return null;

    if (animated is _AnimatedValue<double>) {
      return animated.currentValue;
    }
    return null;
  }

  /// Get the interpolated zoom value.
  double? get interpolatedZoom => _animatedZoom?.currentValue;

  /// Get the interpolated pan value.
  Vector2? get interpolatedPan => _animatedPan?.currentValue;

  /// Get the interpolated rotation value.
  Vector3? get interpolatedRotation => _animatedRotation?.currentValue;

  /// Record when the user finds an interesting spot.
  ///
  /// Triggers celebration effects when multiple interesting spots
  /// are found in quick succession.
  void recordInterestingSpot() {
    final now = DateTime.now();

    if (_lastInterestingSpotTime != null) {
      final elapsed = now.difference(_lastInterestingSpotTime!);
      if (elapsed.inSeconds < 30) {
        _interestingSpotCount++;

        // Trigger celebration after finding 3 interesting spots quickly
        if (_interestingSpotCount >= 3) {
          _triggerCelebration();
          _interestingSpotCount = 0;
        }
      } else {
        _interestingSpotCount = 1;
      }
    } else {
      _interestingSpotCount = 1;
    }

    _lastInterestingSpotTime = now;
    _interestingSpotController.add(null);
  }

  void _triggerCelebration() {
    _isCelebrating = true;
    notifyListeners();

    // Reset celebration after animation. Keep the timer cancellable so a
    // disposed controller cannot receive a delayed notifyListeners callback.
    _celebrationTimer?.cancel();
    _celebrationTimer = Timer(const Duration(milliseconds: 2500), () {
      _celebrationTimer = null;

[167 more lines in file. Use offset=361 to continue.]

      _isCelebrating = false;
      notifyListeners();
    });
  }

  /// Manually trigger a celebration effect.
  void celebrate() {
    _triggerCelebration();
  }

  void _finishMorphTransition() {
    _morphProgress = 1.0;
    _previousModuleId = null;
    _checkTransitionComplete();
  }

  void _checkTransitionComplete() {
    if (_animatedParams.isEmpty &&
        _animatedZoom == null &&
        _animatedPan == null &&
        _animatedRotation == null &&
        _morphProgress >= 1.0) {
      _isTransitioning = false;
      notifyListeners();
    }
  }

  /// Update all animations for the current frame.
  void tick() {
    var needsUpdate = false;

    if (_tickAnimatedParameters()) needsUpdate = true;

    if (_animatedZoom?.tick() == true) needsUpdate = true;
    if (_animatedPan?.tick() == true) needsUpdate = true;
    if (_animatedRotation?.tick() == true) needsUpdate = true;

    if (needsUpdate) {
      notifyListeners();
    }
  }

  bool _tickAnimatedParameters() {
    var needsUpdate = false;

    // Completion callbacks remove entries from [_animatedParams]. Snapshot the
    // values first so a completed parameter does not mutate the map currently
    // being iterated.
    for (final animated in _animatedParams.values.toList(growable: false)) {
      if (animated.tick()) {
        needsUpdate = true;
      }
    }

    return needsUpdate;
  }

  @override
  void dispose() {
    _morphTimer?.cancel();
    _celebrationTimer?.cancel();

    // Close stream controller before disposing
    if (!_interestingSpotController.isClosed) {
      _interestingSpotController.close();
    }

    super.dispose();
  }
}

/// Internal animated value helper.
class _AnimatedValue<T> {
  final T from;
  final T to;
  final Duration duration;
  final Curve curve;
  final VoidCallback? onComplete;

  final DateTime _startTime = DateTime.now();
  bool _completed = false;

  _AnimatedValue({
    required this.from,
    required this.to,
    required this.duration,
    required this.curve,
    this.onComplete,
  });

  AnimatedElapsedProgress get _elapsedProgress => AnimatedElapsedProgress(
        duration: duration,
        elapsed: DateTime.now().difference(_startTime),
      );

  double get _progress => _elapsedProgress.value;

  double get _curvedProgress => curve.transform(_progress);

  bool get isComplete => _elapsedProgress.isComplete;

  T get currentValue {
    final t = _curvedProgress;

    if (T == double) {
      return _lerpDouble(from as double, to as double, t) as T;
    } else if (T == Vector2) {
      return _lerpVector2(from as Vector2, to as Vector2, t) as T;
    } else if (T == Vector3) {
      return _lerpVector3(from as Vector3, to as Vector3, t) as T;
    }
    return to;
  }

  double _lerpDouble(double a, double b, double t) => a + (b - a) * t;

  Vector2 _lerpVector2(Vector2 a, Vector2 b, double t) {
    return Vector2(
      a.x + (b.x - a.x) * t,
      a.y + (b.y - a.y) * t,
    );
  }

  Vector3 _lerpVector3(Vector3 a, Vector3 b, double t) {
    return Vector3(
      a.x + (b.x - a.x) * t,
      a.y + (b.y - a.y) * t,
      a.z + (b.z - a.z) * t,
    );
  }

  /// Returns true if the animation is still running.
  bool tick() {
    if (_completed) return false;

    if (isComplete && !_completed) {
      _completed = true;
      onComplete?.call();
      return false;
    }

    return !_completed;
  }
}

/// Mixin to add animation capabilities to FractalController.
mixin AnimatedFractalMixin on ChangeNotifier {
  AnimatedFractalController? _animationController;

  /// The animation controller for smooth transitions.
  AnimatedFractalController get animationController {
    _animationController ??= AnimatedFractalController();
    return _animationController!;
  }

  /// Set a custom animation controller.
  set animationController(AnimatedFractalController controller) {
    _animationController = controller;
  }

  @override
  void dispose() {
    _animationController?.dispose();
    super.dispose();
  }
}

import 'dart:async';

import 'package:flutter/material.dart';
import 'package:flutter_fractals/core/services/animation_controller_service.dart';
