// A small lexer for a restricted Fractint-like .frm subset.
//
// Supported tokens (initial subset):
// - identifiers: [A-Za-z_][A-Za-z0-9_]*
// - numbers: 123, 1.23, .5, 1e-3
// - punctuation: { } ( ) , : = + - * /
// - comments: ; to end of line

enum FrmTokKind {
  ident,
  number,
  lBrace,
  rBrace,
  lParen,
  rParen,
  comma,
  colon,
  eq,
  plus,
  minus,
  star,
  slash,
  newline,
  eof,
}

final class FrmTok {
  const FrmTok(this.kind, this.lexeme, this.offset);

  final FrmTokKind kind;
  final String lexeme;
  final int offset;

  @override
  String toString() => '$kind("$lexeme")@$offset';
}

final class FrmLexer {
  FrmLexer(this.src);

  final String src;
  int _i = 0;

  List<FrmTok> tokenize() {
    final out = <FrmTok>[];
    while (true) {
      final tok = _next();
      out.add(tok);
      if (tok.kind == FrmTokKind.eof) return out;
    }
  }

  FrmTok _next() {
    _skipSpaces();
    if (_i >= src.length) return FrmTok(FrmTokKind.eof, '', _i);

    final c = src.codeUnitAt(_i);

    // newline
    if (c == 0x0A) {
      _i++;
      return FrmTok(FrmTokKind.newline, '\n', _i - 1);
    }
    if (c == 0x0D) {
      // CRLF or CR
      final start = _i;
      _i++;
      if (_i < src.length && src.codeUnitAt(_i) == 0x0A) _i++;
      return FrmTok(FrmTokKind.newline, '\n', start);
    }

    // comment ;...
    if (c == 0x3B) {
      while (_i < src.length) {
        final cc = src.codeUnitAt(_i);
        if (cc == 0x0A || cc == 0x0D) break;
        _i++;
      }
      // emit newline separately in next call
      return _next();
    }

    switch (c) {
      case 0x7B: // {
        _i++;
        return FrmTok(FrmTokKind.lBrace, '{', _i - 1);
      case 0x7D: // }
        _i++;
        return FrmTok(FrmTokKind.rBrace, '}', _i - 1);
      case 0x28: // (
        _i++;
        return FrmTok(FrmTokKind.lParen, '(', _i - 1);
      case 0x29: // )
        _i++;
        return FrmTok(FrmTokKind.rParen, ')', _i - 1);
      case 0x2C: // ,
        _i++;
        return FrmTok(FrmTokKind.comma, ',', _i - 1);
      case 0x3A: // :
        _i++;
        return FrmTok(FrmTokKind.colon, ':', _i - 1);
      case 0x3D: // =
        _i++;
        return FrmTok(FrmTokKind.eq, '=', _i - 1);
      case 0x2B: // +
        _i++;
        return FrmTok(FrmTokKind.plus, '+', _i - 1);
      case 0x2D: // -
        _i++;
        return FrmTok(FrmTokKind.minus, '-', _i - 1);
      case 0x2A: // *
        _i++;
        return FrmTok(FrmTokKind.star, '*', _i - 1);
      case 0x2F: // /
        _i++;
        return FrmTok(FrmTokKind.slash, '/', _i - 1);
    }

    if (_isDigit(c) || c == 0x2E /* . */) {
      return _number();
    }

    if (_isAlpha(c) || c == 0x5F /* _ */) {
      return _ident();
    }

    throw FormatException('Unexpected character: ${String.fromCharCode(c)}', src, _i);
  }

  void _skipSpaces() {
    while (_i < src.length) {
      final c = src.codeUnitAt(_i);
      if (c == 0x20 || c == 0x09) {
        _i++;
        continue;
      }
      break;
    }
  }

  FrmTok _ident() {
    final start = _i;
    _i++;
    while (_i < src.length) {
      final c = src.codeUnitAt(_i);
      if (_isAlphaNum(c) || c == 0x5F) {
        _i++;
      } else {
        break;
      }
    }
    return FrmTok(FrmTokKind.ident, src.substring(start, _i), start);
  }

  FrmTok _number() {
    final start = _i;

    bool sawDigit = false;

    // int part or leading '.'
    if (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
      sawDigit = true;
      while (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
        _i++;
      }
    }

    // decimal
    if (_i < src.length && src.codeUnitAt(_i) == 0x2E /* . */) {
      _i++;
      while (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
        sawDigit = true;
        _i++;
      }
    }

    if (!sawDigit) {
      throw FormatException('Invalid number', src, start);
    }

    // exponent
    if (_i < src.length) {
      final c = src.codeUnitAt(_i);
      if (c == 0x65 /* e */ || c == 0x45 /* E */) {
        _i++;
        if (_i < src.length) {
          final s = src.codeUnitAt(_i);
          if (s == 0x2B /* + */ || s == 0x2D /* - */) _i++;
        }
        final expStart = _i;
        while (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
          _i++;
        }
        if (expStart == _i) {
          throw FormatException('Invalid exponent', src, expStart);
        }
      }
    }

    return FrmTok(FrmTokKind.number, src.substring(start, _i), start);
  }

  static bool _isDigit(int c) => c >= 0x30 && c <= 0x39;
  static bool _isAlpha(int c) => (c >= 0x41 && c <= 0x5A) || (c >= 0x61 && c <= 0x7A);
  static bool _isAlphaNum(int c) => _isAlpha(c) || _isDigit(c);
}

import 'frm_ast.dart';
import 'frm_lexer.dart';
import 'frm_number_literal.dart';

/// Parser for a small Fractint-style .frm subset.
///
/// Current supported subset:
/// - Multiple formulas per file.
/// - `name { <init-stmts> : <iter-stmts> }`
/// - Stmts: `<ident> = <expr>` separated by newlines.
/// - Expr: numbers, identifiers, (re,im) complex literals, + - * / with parens.
///
/// This is intentionally small; we’ll extend it iteratively with functions,
/// power, comparisons, and bailout conditions once golden iteration tests are in.
bool isFrmStatementBoundary(FrmTokKind kind) =>
    kind == FrmTokKind.newline ||
    kind == FrmTokKind.colon ||
    kind == FrmTokKind.rBrace ||
    kind == FrmTokKind.eof;

bool isFrmFormulaBodyEnd(FrmTokKind kind) =>
    kind == FrmTokKind.rBrace || kind == FrmTokKind.eof;

final class FrmParser {
  FrmParser(String src) : _toks = FrmLexer(src).tokenize();

  final List<FrmTok> _toks;
  int _p = 0;

  FrmFile parseFile() {
    final formulas = <FrmFormula>[];
    _skipNewlines();
    while (!_peekIs(FrmTokKind.eof)) {
      formulas.add(_parseFormula());
      _skipNewlines();
    }
    return FrmFile(formulas);
  }

  FrmFormula _parseFormula() {
    final nameTok = _expect(FrmTokKind.ident, 'Expected formula name');
    _skipNewlines();
    _expect(FrmTokKind.lBrace, 'Expected "{" after formula name');

    final init = <FrmStmt>[];
    final iter = <FrmStmt>[];

    _skipNewlines();
    while (!_peekIs(FrmTokKind.colon)) {
      _expectInitSectionContinues();
      final stmt = _parseStmt();
      init.add(stmt);
      _skipNewlines();
    }

    _expect(FrmTokKind.colon, 'Expected ":" separating init/iter');
    _skipNewlines();

    while (!_peekIs(FrmTokKind.rBrace)) {
      if (_peekIs(FrmTokKind.eof)) {
        throw FormatException('Unterminated formula body', '', _peek().offset);
      }
      final stmt = _parseStmt();
      iter.add(stmt);
      _skipNewlines();
    }

    _expect(FrmTokKind.rBrace, 'Expected "}"');

    return FrmFormula(name: nameTok.lexeme, init: init, iter: iter);
  }

  FrmStmt _parseStmt() {
    final name = _expect(FrmTokKind.ident, 'Expected identifier').lexeme;
    _expect(FrmTokKind.eq, 'Expected "="');
    final expr = _parseExpr();
    _expectStmtBoundary();
    return FrmAssign(name, expr);
  }

  void _expectInitSectionContinues() {
    final tok = _peek();
    if (!isFrmFormulaBodyEnd(tok.kind)) return;
    if (tok.kind == FrmTokKind.eof) {
      throw FormatException('Unterminated formula body', '', tok.offset);
    }
    throw FormatException('Expected ":" in formula body', '', tok.offset);
  }

  void _expectStmtBoundary() {
    final tok = _peek();
    if (!isFrmStatementBoundary(tok.kind)) {
      throw FormatException('Expected newline after statement', '', tok.offset);
    }
  }

  FrmExpr _parseExpr() => _parseAddSub();

  FrmExpr _parseAddSub() {
    var expr = _parseMulDiv();
    while (true) {
      if (_match(FrmTokKind.plus)) {
        expr = FrmBinary(FrmBinaryOp.add, expr, _parseMulDiv());
        continue;
      }
      if (_match(FrmTokKind.minus)) {
        expr = FrmBinary(FrmBinaryOp.sub, expr, _parseMulDiv());
        continue;
      }
      return expr;
    }
  }

  FrmExpr _parseMulDiv() {
    var expr = _parsePrimary();
    while (true) {
      if (_match(FrmTokKind.star)) {
        expr = FrmBinary(FrmBinaryOp.mul, expr, _parsePrimary());
        continue;
      }
      if (_match(FrmTokKind.slash)) {
        expr = FrmBinary(FrmBinaryOp.div, expr, _parsePrimary());
        continue;
      }
      return expr;
    }
  }

  FrmExpr _parsePrimary() {
    if (_match(FrmTokKind.number)) {
      return FrmNumber(FrmNumberLiteral.fromToken(_prev()).parseFinite());
    }

    if (_match(FrmTokKind.ident)) {
      return FrmVar(_prev().lexeme);
    }

    if (_match(FrmTokKind.lParen)) {
      // Could be (expr) or (re,im)
      final first = _parseExpr();
      if (_match(FrmTokKind.comma)) {
        final second = _parseExpr();
        _expect(FrmTokKind.rParen, 'Expected ")"');
        return FrmComplexLiteral(first, second);
      }
      _expect(FrmTokKind.rParen, 'Expected ")"');
      return first;
    }

    if (_match(FrmTokKind.minus)) {
      // unary minus: -x  => (0 - x)
      return FrmBinary(FrmBinaryOp.sub, const FrmNumber(0), _parsePrimary());
    }

    throw FormatException('Expected expression', '', _peek().offset);
  }

  void _skipNewlines() {
    while (_match(FrmTokKind.newline)) {}
  }

  bool _match(FrmTokKind kind) {
    if (_peekIs(kind)) {
      _p++;
      return true;
    }
    return false;
  }

  FrmTok _expect(FrmTokKind kind, String msg) {
    final tok = _peek();
    if (tok.kind != kind) {
      throw FormatException(msg, '', tok.offset);
    }
    _p++;
    return tok;
  }

  FrmTok _peek() => _toks[_p];
  FrmTok _prev() => _toks[_p - 1];
  bool _peekIs(FrmTokKind k) => _peek().kind == k;
}

import 'package:flutter_fractals/features/formulas/frm/complex.dart';
import 'package:flutter_fractals/features/formulas/frm/frm_ast.dart';
import 'package:flutter_fractals/features/formulas/frm/frm_parser.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('FrmParser (subset)', () {
    test('parses multiple formulas with init/iter sections', () {
      const src = r'''
; comment
Mandelbrot {
  z = (0,0)
  c = pixel
:
  z = z*z + c
}

Julia {
  z = pixel
  c = (0.285, 0.01)
:
  z = z*z + c
}
''';

      final file = FrmParser(src).parseFile();
      expect(
          file.formulas.map((f) => f.name).toList(), ['Mandelbrot', 'Julia']);
      expect(file.formulas[0].init.length, 2);
      expect(file.formulas[0].iter.length, 1);
    });

    test('rejects adjacent assignments without a newline separator', () {
      const src = r'''
Test {
  z = (0,0) c = pixel
:
  z = z*z + c
}
''';

      expect(
        () => FrmParser(src).parseFile(),
        throwsA(
          isA<FormatException>().having(
            (e) => e.message,
            'message',
            'Expected newline after statement',
          ),
        ),
      );
    });

    test('reports unterminated body when EOF appears before section separator',
        () {
      const src = r'''
Test {
  z = (0,0)
''';

      expect(
        () => FrmParser(src).parseFile(),
        throwsA(
          isA<FormatException>().having(
            (e) => e.message,
            'message',
            'Unterminated formula body',
          ),
        ),
      );
    });

    test('rejects complex-valued components inside complex literals', () {
      const src = r'''
Test {
  z = ((1,2), 3)
:
  z = z
}
''';

      final formula = FrmParser(src).parseFile().formulas.single;
      final ctx = FrmEvalContext(vars: {'pixel': const Complex(0, 0)});

      expect(
        () => formula.init.single.run(ctx),
        throwsA(
          isA<StateError>().having(
            (e) => e.message,
            'message',
            contains(
                'Complex literal components must evaluate to real scalars'),
          ),
        ),
      );
    });

    test('rejects non-finite numeric literals before evaluation', () {
      const src = r'''
Test {
  z = 1e999
:
  z = z
}
''';

      expect(
        () => FrmParser(src).parseFile(),
        throwsA(
          isA<FormatException>().having(
            (e) => e.message,
            'message',
            'Numeric literal must be finite',
          ),
        ),
      );
    });

    test('evaluates a simple iter statement', () {
      const src = r'''
Test {
  z = (0,0)
  c = (1,0)
:
  z = z*z + c
}
''';

      final formula = FrmParser(src).parseFile().formulas.single;
      final ctx = FrmEvalContext(vars: {
        'z': const Complex(0, 0),
        'c': const Complex(1, 0),
        'pixel': const Complex(0, 0),
      });

      for (final s in formula.init) {
        s.run(ctx);
      }
      // z=(0,0), c=(1,0)
      expect(ctx.vars['z']!.re, 0);
      expect(ctx.vars['c']!.re, 1);

      for (final s in formula.iter) {
        s.run(ctx);
      }
      // z = 0*0 + 1
      expect(ctx.vars['z']!.re, closeTo(1, 1e-12));
      expect(ctx.vars['z']!.im, closeTo(0, 1e-12));
    });

    test('returns immutable parse result lists', () {
      const src = r'''
Test {
  z = (0,0)
:
  z = z*z
}
''';

      final file = FrmParser(src).parseFile();
      final formula = file.formulas.single;

      expect(
        () => file.formulas.add(
          FrmFormula(name: 'Other', init: const [], iter: const []),
        ),
        throwsUnsupportedError,
      );
      expect(
        () => formula.init.add(const FrmAssign('c', FrmVar('pixel'))),
        throwsUnsupportedError,
      );
      expect(
        () => formula.iter.clear(),
        throwsUnsupportedError,
      );
    });
  });
}

import 'dart:math' as math;
import 'dart:ui';

/// Replayable geometry for the 2D fractal minimap.
///
/// The widget paints a tiny overview and an indicator for the currently visible
/// renderer viewport. Keeping the coordinate math pure lets tests characterize
/// assumptions about zoom samples, minimap size, and renderer aspect ratio
/// without relying on a canvas paint pass.
final class MiniMapGeometry {
  static const double defaultZoom = 1.0;
  static const double minimumIndicatorDimension = 4.0;

  /// Fractal-plane span represented by the minimap overview on each axis.
  static const double overviewWorldSpan = 4.0;

  const MiniMapGeometry._();

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return defaultZoom;
    return zoom;
  }

  static Offset normalizePan(Offset pan) {
    return Offset(
      pan.dx.isFinite ? pan.dx : 0.0,
      pan.dy.isFinite ? pan.dy : 0.0,
    );
  }

  /// Maps an absolute fractal-plane pan center to minimap pixels.
  static Offset centerForPan({
    required Offset pan,
    required Size minimapSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    final safePan = normalizePan(pan);
    return Offset(
      width / 2.0 + safePan.dx * width / overviewWorldSpan,
      height / 2.0 + safePan.dy * height / overviewWorldSpan,
    );
  }

  /// Inverse of [centerForPan] for tap-to-pan jumps.
  static Offset panForCenter({
    required Offset center,
    required Size minimapSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    final safeCenter = Offset(
      center.dx.isFinite ? center.dx : width / 2.0,
      center.dy.isFinite ? center.dy : height / 2.0,
    );
    return Offset(
      (safeCenter.dx / width - 0.5) * overviewWorldSpan,
      (safeCenter.dy / height - 0.5) * overviewWorldSpan,
    );
  }

  static Rect viewportRect({
    required Offset pan,
    required double zoom,
    required Size minimapSize,
    required Size viewportSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Rect.zero;

    final safePan = normalizePan(pan);
    final safeZoom = normalizeZoom(zoom);
    final safeViewportSize = _positiveFiniteViewportSize(viewportSize);
    final viewportShortSide = math.min(
      safeViewportSize.width,
      safeViewportSize.height,
    );
    final viewportWidthScale = safeViewportSize.width / viewportShortSide;
    final viewportHeightScale = safeViewportSize.height / viewportShortSide;

    final baseViewportWidth = (2.0 / safeZoom) * (width / overviewWorldSpan);
    final baseViewportHeight = (2.0 / safeZoom) * (height / overviewWorldSpan);
    final center = centerForPan(pan: safePan, minimapSize: minimapSize);

    return Rect.fromCenter(
      center: center,
      width: _clampIndicatorDimension(
        baseViewportWidth * viewportWidthScale,
        width,
      ),
      height: _clampIndicatorDimension(
        baseViewportHeight * viewportHeightScale,
        height,
      ),
    );
  }

  static Offset panForTap({
    required Offset localPosition,
    required Size minimapSize,
    required double zoom,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    // Pan is an absolute fractal-plane center; zoom changes the viewport
    // indicator size, not which overview coordinate a tap selects.
    return panForCenter(center: localPosition, minimapSize: minimapSize);
  }

  static double _positiveFiniteOrZero(double value) {
    return value.isFinite && value > 0.0 ? value : 0.0;
  }

  static Size _positiveFiniteViewportSize(Size size) {
    if (_positiveFiniteOrZero(size.width) == 0.0 ||
        _positiveFiniteOrZero(size.height) == 0.0) {
      return const Size(1, 1);
    }
    return size;
  }

  static double _clampIndicatorDimension(double value, double extent) {
    final lower = math.min(minimumIndicatorDimension, extent);
    if (!value.isFinite || value <= 0.0) return lower;
    return value.clamp(lower, extent).toDouble();
  }
}

import 'package:flutter/material.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/features/minimap/geometry/minimap_geometry.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:provider/provider.dart';
import 'package:vector_math/vector_math.dart' as vm;

/// A minimap overlay showing the current viewport position within a fractal.
class FractalMiniMap extends StatelessWidget {
  final Size viewportSize;
  final double size;
  final bool show3DIndicator;

  const FractalMiniMap({
    super.key,
    required this.viewportSize,
    this.size = 120,
    this.show3DIndicator = true,
  });

  @override
  Widget build(BuildContext context) {
    return Consumer<FractalController>(
      builder: (context, controller, _) {
        final viewState = controller.view;
        final is3D = controller.module.dimension == FractalDimension.threeD;

        if (is3D && show3DIndicator) {
          // For 3D fractals, show zoom indicator only
          return _ZoomIndicator(zoom: viewState.zoom);
        }

        return GestureDetector(
          onTapDown: (details) =>
              _handleTap(context, controller, details.localPosition),
          onPanUpdate: (details) =>
              _handleTap(context, controller, details.localPosition),
          child: Container(
            width: size,
            height: size,
            decoration: BoxDecoration(
              color: Colors.black54,
              borderRadius: BorderRadius.circular(8),
              border: Border.all(color: Colors.white24),
            ),
            child: Stack(
              children: [
                // Grid lines
                CustomPaint(
                  size: Size(size, size),
                  painter: _GridPainter(),
                ),
                // Viewport rectangle
                CustomPaint(
                  size: Size(size, size),
                  painter: _ViewportPainter(
                    pan: Offset(viewState.pan.x, viewState.pan.y),
                    zoom: viewState.zoom,
                    viewportSize: viewportSize,
                  ),
                ),
                // Center dot
                Center(
                  child: Container(
                    width: 6,
                    height: 6,
                    decoration: BoxDecoration(
                      color: Colors.red,
                      shape: BoxShape.circle,
                      border: Border.all(color: Colors.white, width: 1),
                    ),
                  ),
                ),
                // Zoom indicator
                Positioned(
                  bottom: 4,
                  left: 0,
                  right: 0,
                  child: _ZoomPill(zoom: viewState.zoom),
                ),
              ],
            ),
          ),
        );
      },
    );
  }

  void _handleTap(
    BuildContext context,
    FractalController controller,
    Offset localPosition,
  ) {
    final pan = MiniMapGeometry.panForTap(
      localPosition: localPosition,
      minimapSize: Size(size, size),
      zoom: controller.view.zoom,
    );

    controller.updatePan(vm.Vector2(pan.dx, pan.dy));
  }
}

class _ZoomIndicator extends StatelessWidget {
  final double zoom;
  const _ZoomIndicator({required this.zoom});

  @override
  Widget build(BuildContext context) {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
      decoration: BoxDecoration(
        color: Colors.black54,
        borderRadius: BorderRadius.circular(16),
      ),
      child: Text(
        'Zoom: ${zoom.toStringAsFixed(1)}×',
        style: const TextStyle(color: Colors.white, fontSize: 12),
      ),
    );
  }
}

class _ZoomPill extends StatelessWidget {
  final double zoom;
  const _ZoomPill({required this.zoom});

  @override
  Widget build(BuildContext context) {
    return Center(
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
        decoration: BoxDecoration(
          color: Colors.black87,
          borderRadius: BorderRadius.circular(8),
        ),
        child: Text(
          '${zoom.toStringAsFixed(0)}×',
          style: const TextStyle(color: Colors.white70, fontSize: 10),
        ),
      ),
    );
  }
}

class _GridPainter extends CustomPainter {
  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = Colors.white12
      ..strokeWidth = 0.5;

    // Draw grid
    for (var i = 1; i < 4; i++) {
      final x = size.width * i / 4;
      final y = size.height * i / 4;
      canvas.drawLine(Offset(x, 0), Offset(x, size.height), paint);
      canvas.drawLine(Offset(0, y), Offset(size.width, y), paint);
    }
  }

  @override
  bool shouldRepaint(covariant CustomPainter oldDelegate) => false;
}

class _ViewportPainter extends CustomPainter {
  final Offset pan;
  final double zoom;
  final Size viewportSize;

  _ViewportPainter({
    required this.pan,
    required this.zoom,
    required this.viewportSize,
  });

  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = Colors.cyan
      ..style = PaintingStyle.stroke
      ..strokeWidth = 2;

    final rect = MiniMapGeometry.viewportRect(
      pan: pan,
      zoom: zoom,
      minimapSize: size,
      viewportSize: viewportSize,
    );

    canvas.drawRect(rect, paint);
  }

  @override
  bool shouldRepaint(covariant _ViewportPainter oldDelegate) {
    return pan != oldDelegate.pan ||
        zoom != oldDelegate.zoom ||
        viewportSize != oldDelegate.viewportSize;
  }
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time/catalog.dart';
import 'package:flutter_fractals/core/modules/builders/raymarched_3d/catalog.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/catalog/catalog_entry.dart';

/// Catalog data source for the Explore screen.
///
/// Phase 1: derives entries from currently implemented modules while assigning
/// stable catalog IDs. This keeps IDs future-proof for PRD-200 ingest.
class CatalogRepository {
  final List<CatalogEntry> entries;

  const CatalogRepository({required this.entries});

  factory CatalogRepository.fromRegistry(ModuleRegistry registry) {
    final categoriesById = {
      for (final config in escapeTimeCatalog) config.id: config.category,
      for (final config in raymarched3DCatalog) config.id: config.category,
    };

    return CatalogRepository(
      entries: registry.modules
          .map(
            (module) => CatalogEntry(
              // Stable prefix to decouple future module refactors from IDs.
              catalogId: 'core.${module.id}',
              module: module,
              category: categoriesById[module.id] ??
                  (module.dimension == FractalDimension.threeD
                      ? '3D Fractals'
                      : 'Other'),
            ),
          )
          .toList(growable: false),
    );
  }

  CatalogEntry byCatalogId(String catalogId) {
    return entries.firstWhere((entry) => entry.catalogId == catalogId);
  }

  @visibleForTesting
  Set<String> allIds() => entries.map((e) => e.catalogId).toSet();
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';

/// Stable catalog entry used by the redesigned browser.
///
/// This is intentionally separate from [FractalModule] so we can scale the
/// catalog to many entries (e.g. PRD 200) while still mapping to currently
/// implemented render modules.
@immutable
class CatalogEntry {
  /// Stable ID for catalog persistence, analytics, and deep links.
  ///
  /// Must never change once published.
  final String catalogId;

  /// Backing runtime fractal module that can render this entry today.
  final FractalModule module;

  /// Display category used to group entries in the catalog UI.
  final String category;

  /// Optional search aliases used by catalog filtering.
  final List<String> aliases;

  const CatalogEntry({
    required this.catalogId,
    required this.module,
    required this.category,
    this.aliases = const [],
  });
}

