import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/features/catalog/catalog_repository.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('CatalogRepository', () {
    test('creates stable prefixed IDs from module registry', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(repo.entries, isNotEmpty);
      expect(repo.entries.length, registry.modules.length);
      expect(repo.entries.first.catalogId, startsWith('core.'));
      expect(repo.byCatalogId('core.mandelbrot').module.id, 'mandelbrot');
    });

    test('catalog IDs are unique', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(repo.allIds().length, repo.entries.length);
    });

    test('keeps intended 3D runtime modules for implemented 3D catalog ids', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(
        repo.byCatalogId('core.quaternion_julia_3d').module.dimension,
        FractalDimension.threeD,
      );
      expect(
        repo.byCatalogId('core.dual_quaternion_julia').module.dimension,
        FractalDimension.threeD,
      );
      expect(
        repo.byCatalogId('core.mandelbox_shape_inversion').module.dimension,
        FractalDimension.threeD,
      );
    });
  });
}

import 'package:flutter/material.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/core/theme/app_theme.dart';
import 'package:flutter_fractals/features/catalog/fractal_catalog_screen.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:provider/provider.dart';
import 'package:shared_preferences/shared_preferences.dart';

void main() {
  setUp(() {
    TestWidgetsFlutterBinding.ensureInitialized();
    SharedPreferences.setMockInitialValues({});
  });

  Future<void> pumpCatalog(WidgetTester tester) async {
    final registry = ModuleRegistry();

    await tester.pumpWidget(
      MultiProvider(
        providers: [
          Provider<ModuleRegistry>.value(value: registry),
          ChangeNotifierProvider<FractalController>(
            create: (_) => FractalController(registry),
          ),
        ],
        child: const MaterialApp(
          locale: Locale('en'),
          localizationsDelegates: AppLocalizations.localizationsDelegates,
          supportedLocales: AppLocalizations.supportedLocales,
          home: Scaffold(
            body: FractalCatalogScreen(),
          ),
        ),
      ),
    );

    // Bounded pumps instead of pumpAndSettle: catalog shimmer animations repeat.
    await tester.pump();
    await tester.pump(const Duration(milliseconds: 100));
  }

  Future<void> showSearch(WidgetTester tester) async {
    await tester.tap(find.byIcon(Icons.search_rounded));
    await tester.pump();
    await tester.pump();

    expect(find.byKey(const Key('catalogSearchField')), findsOneWidget);
  }

  int allDimensionCount(WidgetTester tester) {
    final countTexts = tester
        .widgetList<Text>(
          find.descendant(
            of: find.byKey(const Key('catalogDimensionChip_all')),
            matching: find.byType(Text),
          ),
        )
        .map((text) => text.data)
        .whereType<String>()
        .toList();
    return int.parse(countTexts.last);
  }

  testWidgets('Catalog search filters fractal modules', (tester) async {
    await pumpCatalog(tester);
    final initialCount = allDimensionCount(tester);
    await showSearch(tester);

    await tester.enterText(
      find.byKey(const Key('catalogSearchField')),
      'Julia',
    );
    await tester.pump(const Duration(milliseconds: 300));

    expect(find.text('Julia'), findsWidgets);
    expect(allDimensionCount(tester), lessThan(initialCount));

    await tester.pump(const Duration(seconds: 3));
  });

  testWidgets('Catalog search field uses the focused visual state',
      (tester) async {
    await pumpCatalog(tester);
    await showSearch(tester);

    final searchField = tester.widget<TextField>(
      find.byKey(const Key('catalogSearchField')),
    );
    expect(searchField.focusNode?.hasFocus, isTrue);

    final container = tester.widget<AnimatedContainer>(
      find.byKey(const Key('catalogSearchContainer')),
    );
    final decoration = container.decoration! as BoxDecoration;
    final border = decoration.border! as Border;

    expect(border.top.color, AppColors.primary.withValues(alpha: 0.6));
    expect(border.top.width, 1.5);

    await tester.pump(const Duration(seconds: 3));
  });

  testWidgets('Catalog search debounce waits for the latest edit',
      (tester) async {
    await pumpCatalog(tester);
    await showSearch(tester);

    final initialCount = allDimensionCount(tester);
    final searchField = find.byKey(const Key('catalogSearchField'));
    await tester.enterText(searchField, 'J');
    await tester.pump(const Duration(milliseconds: 150));
    await tester.enterText(searchField, 'Julia');

    // More than 300ms after the first edit, but less than 300ms after the
    // latest edit. Search results should still show the unfiltered catalog.
    await tester.pump(const Duration(milliseconds: 200));
    expect(allDimensionCount(tester), initialCount);

    await tester.pump(const Duration(milliseconds: 100));
    expect(find.text('Julia'), findsWidgets);
    expect(allDimensionCount(tester), lessThan(initialCount));

    await tester.pump(const Duration(seconds: 3));
  });

  testWidgets('Catalog search clear icon resets the applied query immediately',
      (tester) async {
    await pumpCatalog(tester);
    await showSearch(tester);

    final initialCount = allDimensionCount(tester);
    final searchField = find.byKey(const Key('catalogSearchField'));

    await tester.enterText(searchField, 'Julia');
    await tester.pump(const Duration(milliseconds: 300));
    expect(allDimensionCount(tester), lessThan(initialCount));

    await tester.tap(find.byKey(const ValueKey('clear')));
    await tester.pump();

    expect(allDimensionCount(tester), initialCount);

    await tester.pump(const Duration(seconds: 3));
  });
}

import 'dart:async';

/// Cancelable debounce contract for catalog search input.
///
/// A search edit should publish only after [delay] has elapsed without a newer
/// edit. Keeping this behavior behind a small helper makes the timing contract
/// testable instead of relying on stacked [Future.delayed] callbacks.
final class CatalogSearchDebouncer {
  final Duration delay;
  Timer? _timer;

  CatalogSearchDebouncer({
    this.delay = const Duration(milliseconds: 300),
  });

  void schedule(void Function() callback) {
    _timer?.cancel();
    _timer = Timer(delay, callback);
  }

  void cancel() {
    _timer?.cancel();
    _timer = null;
  }

  void dispose() {
    cancel();
  }
}

import 'dart:ui';
import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

/// A function that returns a localized display name for a fractal module.
///
/// Takes an [AppLocalizations] instance and returns the appropriate
/// translated string for the current locale.
typedef ModuleNameBuilder = String Function(AppLocalizations l10n);

/// A function that configures shader uniforms for fractal rendering.
///
/// Called each frame to set the shader's uniform values based on the
/// current [state], canvas [size], and elapsed [time].
///
/// Parameters:
/// - [shader]: The fragment shader to configure
/// - [state]: Current fractal parameters and view state
/// - [size]: Canvas dimensions in logical pixels
/// - [time]: Elapsed time in milliseconds (for animations)
typedef UniformSetter = void Function(
  FragmentShader shader,
  FractalRenderState state,
  Size size,
  double time,
);

/// Defines whether a fractal is rendered in 2D or 3D space.
///
/// This affects gesture behavior (pan vs rotate) and rendering approach.
enum FractalDimension {
  /// 2D fractals rendered on a plane (e.g., Mandelbrot, Julia).
  ///
  /// Supports panning and zooming gestures.
  twoD,

  /// 3D fractals rendered with raymarching (e.g., Mandelbulb).
  ///
  /// Supports rotation and zooming gestures.
  threeD,
}

/// Defines a complete fractal type with its rendering configuration.
///
/// A [FractalModule] encapsulates everything needed to render a specific
/// type of fractal:
/// - Display metadata (name, dimension)
/// - Shader asset path
/// - Configurable parameters with their ranges
/// - Default and built-in presets
/// - Uniform setting logic
///
/// Modules are immutable and registered with [ModuleRegistry] at app startup.
///
/// {@category Modules}
///
/// Example of creating a custom fractal module:
/// ```dart
/// final myModule = FractalModule(
///   id: 'my_fractal',
///   displayName: (l10n) => 'My Fractal',
///   dimension: FractalDimension.twoD,
///   shaderAsset: 'shaders/my_fractal.frag',
///   parameters: [/* ... */],
///   defaultPreset: myDefaultPreset,
///   builtInPresets: [/* ... */],
///   setUniforms: (shader, state, size, time) {
///     // Configure shader uniforms...
///   },
/// );
/// ```
@immutable
class FractalModule {
  /// Unique identifier for this module.
  ///
  /// Used for preset storage, module lookup, and serialization.
  /// Should be a lowercase, snake_case string.
  final String id;

  /// Returns the localized display name for this fractal.
  ///
  /// Example: `(l10n) => l10n.moduleMandelbrot`
  final ModuleNameBuilder displayName;

  /// Whether this is a 2D or 3D fractal.
  ///
  /// Affects gesture handling and rendering approach.
  final FractalDimension dimension;

  /// Path to the GLSL fragment shader asset.
  ///
  /// The shader must be registered in `pubspec.yaml` under `flutter.shaders`.
  /// Example: `'shaders/legacy/diagnostics/mandelbrot.frag'`
  final String shaderAsset;

  /// The configurable parameters for this fractal type.
  ///
  /// Each parameter defines its type, valid range, step size, and default value.
  /// These are used to generate the controls UI and validate user input.
  final List<FractalParameter> parameters;

  /// The default preset applied when this module is first selected.
  ///
  /// Should provide sensible starting values for an attractive render.
  final FractalPreset defaultPreset;

  /// Pre-configured presets included with this module.
  ///
  /// These appear in the preset selector and showcase different
  /// visual configurations of this fractal type.
  final List<FractalPreset> builtInPresets;

  /// Function that sets shader uniforms each frame.
  ///
  /// This bridges the Dart parameter values to the GLSL shader's
  /// uniform variables. The uniform layout must match the shader code.
  final UniformSetter setUniforms;

  /// Creates a new [FractalModule] with the specified configuration.
  ///
  /// All parameters are required to ensure a complete module definition.
  const FractalModule({
    required this.id,
    required this.displayName,
    required this.dimension,
    required this.shaderAsset,
    required this.parameters,
    required this.defaultPreset,
    required this.builtInPresets,
    required this.setUniforms,
  });
}

/// Snapshot of the current fractal rendering state.
///
/// Combines the fractal's mathematical parameters with view state
/// (pan, zoom, rotation) for rendering a single frame.
///
/// This is passed to the [UniformSetter] each frame to configure shaders.
@immutable
class FractalRenderState {
  /// Current parameter values keyed by parameter ID.
  ///
  /// Values are typed according to [FractalParamType]:
  /// - `float`: [double]
  /// - `integer`: [int]
  /// - `boolean`: [bool]
  /// - `enumeration`: depends on options
  final Map<String, Object> params;

  /// Current view transformation state.
  ///
  /// Includes pan offset (2D), zoom level, and rotation angles (3D).
  final FractalViewState view;

  /// Whether to render with a transparent background.
  ///
  /// When true, the shader should output alpha=0 for background pixels.
  /// Used for transparent PNG export.
  final bool transparentBackground;

  /// Creates a new [FractalRenderState] with the given values.
  const FractalRenderState({
    required this.params,
    required this.view,
    required this.transparentBackground,
  });
}

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:vector_math/vector_math.dart';
import 'fractal_view_state.dart';

FractalViewState _snapshotPresetView(FractalViewState view) {
  return FractalViewState(
    pan: view.pan,
    zoom: view.zoom,
    rotation: view.rotation,
  );
}

Map<String, Object> _snapshotPresetParams(Map<String, Object> params) {
  return Map<String, Object>.unmodifiable({
    for (final entry in params.entries)
      entry.key: _snapshotPresetParamValue(entry.value),
  });
}

Map<String, Object> _decodePresetParams(Map params) {
  final decoded = <String, Object>{};
  for (final entry in params.entries) {
    final key = entry.key;
    final value = entry.value;
    if (key == null || value == null) continue;
    decoded[key.toString()] = _snapshotPresetParamValue(value as Object);
  }
  return Map<String, Object>.unmodifiable(decoded);
}

Object _snapshotPresetParamValue(Object value) {
  if (value is List) {
    return List<Object?>.unmodifiable([
      for (final item in value)
        item is Object ? _snapshotPresetParamValue(item) : item,
    ]);
  }

  if (value is Map) {
    return Map<String, Object?>.unmodifiable({
      for (final entry in value.entries)
        entry.key.toString(): entry.value is Object
            ? _snapshotPresetParamValue(entry.value as Object)
            : entry.value,
    });
  }

  return value;
}

