import 'package:flutter_fractals/features/catalog/catalog_entry.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

/// Replayable catalog search query used by the catalog screen.
///
/// The UI debounces text input, then filters entries by localized display name,
/// aliases, stable catalog ID, and category. Keeping the case/whitespace
/// normalization in one pure value object makes search behavior testable without
/// pumping the whole catalog widget.
final class CatalogSearchQuery {
  const CatalogSearchQuery._(this.value);

  factory CatalogSearchQuery.fromText(String text) {
    return CatalogSearchQuery._(text.trim().toLowerCase());
  }

  /// Lower-case, trimmed query text.
  final String value;

  bool get isEmpty => value.isEmpty;

  bool matches(CatalogEntry entry, AppLocalizations l10n) {
    if (isEmpty) return true;

    final name = entry.module.displayName(l10n).toLowerCase();
    final matchesAlias = entry.aliases.any(
      (alias) => alias.toLowerCase().contains(value),
    );

    return name.contains(value) ||
        matchesAlias ||
        entry.catalogId.contains(value) ||
        entry.category.toLowerCase().contains(value);
  }
}

import 'package:flutter/material.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/features/catalog/catalog_entry.dart';
import 'package:flutter_fractals/features/catalog/catalog_filter.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';
import 'package:flutter_test/flutter_test.dart';

FractalModule _module({String displayName = 'Visible Name'}) {
  return FractalModule(
    id: 'dummy_module',
    displayName: (_) => displayName,
    dimension: FractalDimension.twoD,
    shaderAsset: 'shaders/dummy.frag',
    parameters: const [],
    defaultPreset: FractalPreset(
      id: 'dummy-default',
      moduleId: 'dummy_module',
      name: 'Default',
      params: const <String, Object>{},
      view: FractalViewState.initial(),
      createdAt: DateTime.utc(2024),
      isBuiltIn: true,
    ),
    builtInPresets: const [],
    setUniforms: (_, __, ___, ____) {},
  );
}

void main() {
  final l10n = lookupAppLocalizations(const Locale('en'));

  group('CatalogSearchQuery', () {
    test('empty query matches every entry', () {
      final entry = CatalogEntry(
        catalogId: 'core.dummy_module',
        module: _module(),
        category: 'Other',
      );

      expect(CatalogSearchQuery.fromText('   ').matches(entry, l10n), isTrue);
    });

    test('case-folds every searchable entry field', () {
      final entry = CatalogEntry(
        catalogId: 'Core.MixedCaseId',
        module: _module(displayName: 'Visible Name'),
        category: 'Escape Time',
        aliases: const ['Phoenix Alias'],
      );

      expect(CatalogSearchQuery.fromText(' visible ').matches(entry, l10n),
          isTrue);
      expect(CatalogSearchQuery.fromText('PHOENIX').matches(entry, l10n),
          isTrue);
      expect(CatalogSearchQuery.fromText('escape time').matches(entry, l10n),
          isTrue);
      expect(CatalogSearchQuery.fromText('mixedcaseid').matches(entry, l10n),
          isTrue);
    });
  });
}

